// Flatten all locations with company info for map markers
export interface MarkerData {
  id: number;
  companyName: string;
  locationName: string;
  latitude: number;
  longitude: number;
  category: "直接操業" | "バリューチェーン" | "両方" | "情報なし";
  reason: string;
  sourceUrls: string;
}

export const allMarkers: MarkerData[] = companyData.flatMap((company) =>
  company.locations.map((loc) => ({
    id: loc.id,
    companyName: company.companyName,
    locationName: loc.name,
    latitude: loc.latitude,
    longitude: loc.longitude,
    category: loc.category,
    reason: loc.reason,
    sourceUrls: company.sourceUrls,
  }))
);

export const TOTAL_COMPANIES = 65;
